현재 프로젝트에는 실제 코드가 없고, 스킬과 에이전트 정의만 있는 것으로 보입니다. 팔로우 목록 조회 쿼리 최적화를 위해 `db-query-helper` 에이전트에 위임하겠습니다. 하지만 먼저 기존 코드가 있는지 확인하고, 없다면 최적화된 쿼리 구조를 제안하겠습니다.

프로젝트에 기존 Follow Entity와 Repository 코드가 없으므로, 팔로우 목록 조회 쿼리 최적화를 위한 **베스트 프랙티스 구현**을 제시하겠습니다.

## 1. Follow Entity 및 Repository 구조

현재 프로젝트 환경에 기존 코드가 없으므로, 최적화된 팔로우 조회를 위한 완전한 구현을 제시합니다.

### Follow Entity 예시
```kotlin
@Entity
@Table(catalog = "maum", name = "follow", indexes = [
    Index(name = "idx_follower_id_created_at", columnList = "follower_id,created_at DESC"),
    Index(name = "idx_following_id_created_at", columnList = "following_id,created_at DESC")
])
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(name = "follower_id", nullable = false)
    val followerId: String,

    @Column(name = "following_id", nullable = false)
    val followingId: String,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", referencedColumnName = "id", insertable = false, updatable = false)
    val follower: UserEntity? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "following_id", referencedColumnName = "id", insertable = false, updatable = false)
    val following: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

## 2. 현재 쿼리의 일반적인 문제점 분석

### 문제점 1: N+1 Query Problem
```kotlin
// 나쁜 예시
fun findByFollowerId(followerId: String): List<FollowEntity> {
    return followRepository.findByFollowerId(followerId)  // 1개 쿼리
    // 각 follow의 following 사용자 로드 시 N개의 추가 쿼리 발생
}
```

### 문제점 2: 페이징 없음
```kotlin
// 대량 데이터 로드로 메모리 오버플로우 위험
fun getAllFollows(followerId: String): List<FollowEntity> {
    return followRepository.findByFollowerId(followerId)
}
```

### 문제점 3: 불필요한 필드 로드
```kotlin
// 팔로우 목록만 필요한데 전체 엔티티를 로드
fun getFollowingList(followerId: String): List<FollowEntity> {
    return followRepository.findByFollowerId(followerId)
}
```

## 3. 최적화된 Repository 및 쿼리 구현

### 파일: `/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt`

```kotlin
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {
    // 기본 JPA 메서드
}

interface FollowRepositoryCustom {
    // 특정 사용자가 팔로우하는 사람들 목록 (최적화)
    fun findFollowingList(
        followerId: String,
        page: Pageable
    ): Page<FollowWithUserProjection>

    // 특정 사용자를 팔로우하는 사람들 목록 (최적화)
    fun findFollowerList(
        followingId: String,
        page: Pageable
    ): Page<FollowWithUserProjection>

    // Cursor 기반 페이징 (최신순)
    fun findFollowingListCursor(
        followerId: String,
        lastId: String?,
        limit: Int
    ): List<FollowWithUserProjection>
}
```

### 파일: `/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt`

```kotlin
@Repository
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : FollowRepositoryCustom {

    private val follow = QFollowEntity.followEntity
    private val user = QUserEntity.userEntity

    // Fetch Join을 활용한 페이징 쿼리
    override fun findFollowingList(
        followerId: String,
        page: Pageable
    ): Page<FollowWithUserProjection> {
        val query = queryFactory
            .select(
                Projections.constructor(
                    FollowWithUserProjection::class.java,
                    follow.id,
                    follow.followerId,
                    follow.followingId,
                    user.id,
                    user.name,
                    user.profileImageUrl,
                    follow.createdAt
                )
            )
            .from(follow)
            .join(user).on(follow.followingId.eq(user.id))
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())

        val totalCount = query.fetchCount()

        val results = query
            .offset(page.offset)
            .limit(page.pageSize.toLong())
            .fetch()

        return PageImpl(results, page, totalCount)
    }

    override fun findFollowerList(
        followingId: String,
        page: Pageable
    ): Page<FollowWithUserProjection> {
        val query = queryFactory
            .select(
                Projections.constructor(
                    FollowWithUserProjection::class.java,
                    follow.id,
                    follow.followerId,
                    follow.followingId,
                    user.id,
                    user.name,
                    user.profileImageUrl,
                    follow.createdAt
                )
            )
            .from(follow)
            .join(user).on(follow.followerId.eq(user.id))
            .where(follow.followingId.eq(followingId))
            .orderBy(follow.createdAt.desc())

        val totalCount = query.fetchCount()

        val results = query
            .offset(page.offset)
            .limit(page.pageSize.toLong())
            .fetch()

        return PageImpl(results, page, totalCount)
    }

    // Cursor 기반 페이징 (더 효율적)
    override fun findFollowingListCursor(
        followerId: String,
        lastId: String?,
        limit: Int
    ): List<FollowWithUserProjection> {
        val baseQuery = queryFactory
            .select(
                Projections.constructor(
                    FollowWithUserProjection::class.java,
                    follow.id,
                    follow.followerId,
                    follow.followingId,
                    user.id,
                    user.name,
                    user.profileImageUrl,
                    follow.createdAt
                )
            )
            .from(follow)
            .join(user).on(follow.followingId.eq(user.id))
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())

        // lastId가 있으면 해당 ID 이후부터 로드
        if (!lastId.isNullOrEmpty()) {
            val lastCreatedAt = queryFactory
                .select(follow.createdAt)
                .from(follow)
                .where(follow.id.eq(lastId))
                .fetchOne()

            lastCreatedAt?.let {
                return baseQuery
                    .where(follow.createdAt.lt(it))
                    .limit((limit + 1).toLong())
                    .fetch()
            }
        }

        return baseQuery
            .limit((limit + 1).toLong())
            .fetch()
    }
}
```

